#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, na, nb, a[205], b[205], sa = 0, sb = 0, 
    res[10][10] = { // 0输 1赢 2平局
        {2, 0, 0, 1, 0}, 
        {1, 2, 1, 1, 0},
        {1, 0, 2, 0, 1}, 
        {0, 0, 1, 2, 1},
        {1, 1, 0, 0, 2}
    };
    cin >> n >> na >> nb;
    for (int i = 0; i < na; i++) {
        cin >> a[i];
    }
    for (int i = 0; i < nb; i++) {
        cin >> b[i];
    }

    for (int i = 0; i < n; i++) {
        int temp = res[b[i % nb]][a[i % na]];
        if (temp == 0) {
            sa++;
        }
        else if (temp == 1) {
            sb++;
        }
    }
    cout << sa << ' ' << sb;
    return 0;
}
/*
0 剪刀,
1 石头,
2 布,
3 蜥蜴人,
4 斯波克
A B 结果
*/
